import { corsHeaders, jsonResponse } from "./_shared/cors.ts";
import { supabaseServiceClient, supabaseUserClient } from "./_shared/supabase.ts";
import { tellerFetch } from "./_shared/teller_fetch.ts";

type ActionBody = {
  action?: string;
  accountId?: string;
};

Deno.serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }
  if (req.method !== "POST") {
    return jsonResponse({ error: "Method not allowed" }, 405);
  }

  const userClient = supabaseUserClient(req);
  const { data: userData, error: userErr } = await userClient.auth.getUser();
  if (userErr || !userData.user) {
    return jsonResponse({ error: "Unauthorized" }, 401);
  }

  let body: ActionBody;
  try {
    body = await req.json();
  } catch {
    return jsonResponse({ error: "Invalid JSON" }, 400);
  }

  const action = body.action?.trim();
  if (action !== "accounts" && action !== "transactions") {
    return jsonResponse({ error: "Unsupported action" }, 400);
  }

  const admin = supabaseServiceClient();
  const { data: row, error: rowErr } = await admin
    .from("teller_enrollments")
    .select("access_token")
    .eq("user_id", userData.user.id)
    .maybeSingle();

  if (rowErr) {
    return jsonResponse({ error: rowErr.message }, 500);
  }
  if (!row?.access_token) {
    return jsonResponse({ error: "No bank connection. Run Teller Connect first." }, 400);
  }

  const token = row.access_token as string;

  if (action === "accounts") {
    const res = await tellerFetch("/accounts", token);
    const text = await res.text();
    if (!res.ok) {
      return jsonResponse({ error: `Teller accounts failed (${res.status}): ${text}` }, 502);
    }
    try {
      const accounts = JSON.parse(text);
      return jsonResponse({ accounts });
    } catch {
      return jsonResponse({ error: "Invalid JSON from Teller" }, 502);
    }
  }

  const accountId = body.accountId?.trim();
  if (!accountId) {
    return jsonResponse({ error: "Missing accountId" }, 400);
  }

  const path = `/accounts/${encodeURIComponent(accountId)}/transactions?count=50`;
  const res = await tellerFetch(path, token);
  const text = await res.text();
  if (!res.ok) {
    return jsonResponse({ error: `Teller transactions failed (${res.status}): ${text}` }, 502);
  }
  try {
    const transactions = JSON.parse(text);
    return jsonResponse({ transactions });
  } catch {
    return jsonResponse({ error: "Invalid JSON from Teller" }, 502);
  }
});

export const corsHeaders: Record<string, string> = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers":
    "authorization, x-client-info, apikey, content-type, x-supabase-authorization",
  "Access-Control-Allow-Methods": "GET, POST, OPTIONS",
};

export function jsonResponse(body: unknown, status = 200) {
  return new Response(JSON.stringify(body), {
    status,
    headers: { ...corsHeaders, "Content-Type": "application/json" },
  });
}

import { createClient, type SupabaseClient } from "https://esm.sh/@supabase/supabase-js@2.49.4";

export function supabaseUserClient(req: Request): SupabaseClient {
  const url = Deno.env.get("SUPABASE_URL") ?? "";
  const anon = Deno.env.get("SUPABASE_ANON_KEY") ?? "";
  const authorization = req.headers.get("Authorization") ?? "";
  return createClient(url, anon, {
    global: { headers: { Authorization: authorization } },
  });
}

export function supabaseServiceClient(): SupabaseClient {
  const url = Deno.env.get("SUPABASE_URL") ?? "";
  const key = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY") ?? "";
  return createClient(url, key);
}

/**
 * Calls Teller HTTP API with access token (HTTP Basic) and optional mTLS.
 * Sandbox can work without a client cert; development/production require Teller-issued PEMs.
 */
export async function tellerFetch(path: string, accessToken: string, init?: RequestInit): Promise<Response> {
  const basic = btoa(`${accessToken}:`);
  const cert = Deno.env.get("TELLER_CERT_PEM")?.trim();
  const key = Deno.env.get("TELLER_KEY_PEM")?.trim();
  const client = cert && key ? Deno.createHttpClient({ cert, key }) : undefined;
  const url = `https://api.teller.io${path.startsWith("/") ? "" : "/"}${path}`;
  try {
    return await fetch(url, {
      ...init,
      client,
      headers: {
        ...(init?.headers ?? {}),
        Authorization: `Basic ${basic}`,
        Accept: "application/json",
      },
    });
  } finally {
    if (client) client.close();
  }
}
